proof_block:
// The synthetic ensures is wrapped in `(big_conj) ==> det_pop_equal(...)`,
// so the per-run ensures are NOT direct hypotheses in the proof body.
// Discharge the implication explicitly: assume the big conjunction inside
// the by-block (via an `if`) so its facts (in particular the two
// `forall|v:T| post_i@.contains(v) ==> ...` clauses with disjoint triggers)
// are in scope, then drive each conjunct of det_pop_equal pointwise.
assert(({
    &&& (post1_self_.wf())
    &&& (post1_self_.len() == pre_self_.len() - 1)
    &&& (post1_self_@ == pre_self_@.skip(1))
    &&& (r1.0 == pre_self_@[0])
    &&& (r1.1 == pre_self_.get_node_ref(r1.0))
    &&& (forall|v:T| #![auto]
            post1_self_@.contains(v) ==>
                pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v))
    &&& (post2_self_.wf())
    &&& (post2_self_.len() == pre_self_.len() - 1)
    &&& (post2_self_@ == pre_self_@.skip(1))
    &&& (r2.0 == pre_self_@[0])
    &&& (r2.1 == pre_self_.get_node_ref(r2.0))
    &&& (forall|v:T| #![auto]
            post2_self_@.contains(v) ==>
                pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v))
}) ==> det_pop_equal(r1, r2, post1_self_, post2_self_)) by {
    if (post1_self_.wf())
        && (post1_self_.len() == pre_self_.len() - 1)
        && (post1_self_@ == pre_self_@.skip(1))
        && (r1.0 == pre_self_@[0])
        && (r1.1 == pre_self_.get_node_ref(r1.0))
        && (forall|v:T| #![auto]
                post1_self_@.contains(v) ==>
                    pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v))
        && (post2_self_.wf())
        && (post2_self_.len() == pre_self_.len() - 1)
        && (post2_self_@ == pre_self_@.skip(1))
        && (r2.0 == pre_self_@[0])
        && (r2.1 == pre_self_.get_node_ref(r2.0))
        && (forall|v:T| #![auto]
                post2_self_@.contains(v) ==>
                    pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v))
    {
        // Tuple component 0: both runs pin r_i.0 to pre_self_@[0].
        assert(r1.0 == pre_self_@[0]);
        assert(r2.0 == pre_self_@[0]);
        assert(r1.0 == r2.0);

        // Tuple component 1: both runs pin r_i.1 to pre_self_.get_node_ref(r_i.0),
        // and r1.0 == r2.0, so the same get_node_ref value lines up.
        assert(r1.1 == pre_self_.get_node_ref(r1.0));
        assert(r2.1 == pre_self_.get_node_ref(r2.0));
        assert(r1.1 == r2.1);

        // Views (and hence spec_seq, since `view` is an open spec equal to
        // `self.spec_seq@`) are both `pre_self_@.skip(1)`.
        assert(post1_self_@ == pre_self_@.skip(1));
        assert(post2_self_@ == pre_self_@.skip(1));
        assert(post1_self_@ =~= post2_self_@);
        assert(post1_self_@ == post2_self_@);

        // Re-state both `forall|v|` ensures so their (auto) triggers
        // (post_i@.contains(v)) are populated for both runs simultaneously.
        // This is the trigger-alignment step that z3 was missing at the file
        // level — re-emitting them inside the by-block forces the matching
        // loop to fire once for each run.
        assert(forall|v:T| #![auto]
            post1_self_@.contains(v) ==>
                pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v));
        assert(forall|v:T| #![auto]
            post2_self_@.contains(v) ==>
                pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v));

        // Pointwise: for every v in the common post view, the two
        // get_node_ref values both equal pre_self_.get_node_ref(v) and
        // therefore agree with each other.
        assert forall|v:T| #![auto] post1_self_@.contains(v) implies
            post1_self_.get_node_ref(v) == post2_self_.get_node_ref(v) by {
            assert(post2_self_@.contains(v));
            assert(pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v));
            assert(pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v));
        }
    }
}
